// Normalize incoming data
const incoming = $json;
let skus = [];
let options = {};

// Handle all 3 trigger sources
if (incoming.skus) {
  skus = incoming.skus;
  options = incoming.options || {};
} else if (incoming.body && incoming.body.skus) {
  skus = incoming.body.skus;
  options = incoming.body.options || {};
}

if (!skus.length) {
  throw new Error('No SKUs provided. Expected: { "skus": [...] }');
}

// Merge options with config (request options override config)
const mergedConfig = {
  ...CONFIG,
  ENABLE_AI_ENRICHMENT: options.ai_enrichment !== undefined ? options.ai_enrichment : CONFIG.ENABLE_AI_ENRICHMENT,
  ENABLE_AB_VARIANTS:   options.ab_variants   !== undefined ? options.ab_variants   : CONFIG.ENABLE_AB_VARIANTS,
  ENABLE_MULTIMARKET:   options.markets ? options.markets.length > 1 : CONFIG.ENABLE_MULTIMARKET,
  ENABLE_SHEETS_WRITE:  options.sheet_write    !== undefined ? options.sheet_write   : CONFIG.ENABLE_SHEETS_WRITE,
  MARKETS: options.markets || ['nl'],
  source: incoming.source || 'webhook'
};

