// ============================================================
// BATCH SPLITTER — protect against large catalogs
// Splits into chunks of BATCH_SIZE for safe processing
// ============================================================
const { config, skus, total } = $json;
const batchSize = config.BATCH_SIZE || 50;

const batches = [];
for (let i = 0; i < skus.length; i += batchSize) {
  batches.push({
    config,
    skus: skus.slice(i, i + batchSize),
    batch_index: Math.floor(i / batchSize),
    batch_total: Math.ceil(skus.length / batchSize),
    total_skus: total
  });
}

return batches.map(b => ({ json: b }));

