// ── HELPER FUNCTIONS ──────────────────────────────────────────
function detectIntent(category) {
  const cat = (category || '').toLowerCase().trim();
  for (const [k, v] of Object.entries(INTENT)) {
    if (cat.includes(k)) return v;
  }
  return 'transactional';
}

function translatePartName(name, dict) {
  const lower = (name || '').toLowerCase();
  for (const [nl, trans] of Object.entries(dict)) {
    if (lower.includes(nl)) {
      return name.toLowerCase().replace(nl, trans);
    }
  }
  return name;
}

function applyTemplate(tpl, p, market) {
  const usp = (config.USP && config.USP[market]) || config.USP?.nl || 'Gratis verzending';
  // Axle position labels
  const axle_nl = p.axle || (p.part_name.toLowerCase().includes('voor') ? '' : p.part_name.toLowerCase().includes('achter') ? '' : '');
  const axle_de = axle_nl.replace('voor','vorne').replace('achter','hinten').replace('links','links').replace('rechts','rechts');
  const axle_en = axle_nl.replace('voor','Front').replace('achter','Rear').replace('links','Left').replace('rechts','Right');

  const part_name_de = translatePartName(p.part_name, TRANSLATE_DE);
  const part_name_en = translatePartName(p.part_name, TRANSLATE_EN);

  return tpl
    .replace(/\{brand\}/g,       p.brand)
    .replace(/\{part_name\}/g,   p.part_name)
    .replace(/\{part_name_de\}/g,part_name_de)
    .replace(/\{part_name_en\}/g,part_name_en)
    .replace(/\{sku\}/g,         p.sku)
    .replace(/\{make\}/g,        p.make)
    .replace(/\{model\}/g,       p.model)
    .replace(/\{year_from\}/g,   p.year_from)
    .replace(/\{year_to\}/g,     p.year_to)
    .replace(/\{engine\}/g,      p.engine)
    .replace(/\{oem\}/g,         p.oem)
    .replace(/\{size\}/g,        p.size)
    .replace(/\{axle_nl\}/g,     axle_nl)
    .replace(/\{axle_de\}/g,     axle_de)
    .replace(/\{axle_en\}/g,     axle_en)
    .replace(/\{shop\}/g,        config.SHOP_NAME)
    .replace(/\{usp\}/g,         usp)
    .replace(/\{size_label\}/g,  p.size ? `Diameter ${p.size}. ` : '')
    .replace(/\s{2,}/g, ' ')
    .replace(/\s*[—–-]\s*$/, '')
    .replace(/^[\s,—–-]+/, '')
    .trim();
}

function selectBestTitle(formulas, p, market) {
  const candidates = formulas.map(f => applyTemplate(f, p, market));
  // Score by: length proximity to 55 chars, then keyword density
  return candidates.reduce((best, cur) => {
    const scoreCur  = 100 - Math.abs(cur.length  - 55) + (cur.split(' ').length > 4 ? 5 : 0);
    const scoreBest = 100 - Math.abs(best.length - 55) + (best.split(' ').length > 4 ? 5 : 0);
    return scoreCur > scoreBest ? cur : best;
  });
}

function keywordDensityScore(title, p) {
  // Front-loading bonus: primary keywords in first 30 chars
  const front = title.substring(0, 30).toLowerCase();
  let score = 0;
  if (p.brand && front.includes(p.brand.toLowerCase())) score += 15;
  if (p.part_name) {
    const mainWord = p.part_name.toLowerCase().split(' ')[0];
    if (front.includes(mainWord)) score += 15;
    else if (title.toLowerCase().includes(mainWord)) score += 8;
  }
  if (p.make && title.toLowerCase().includes(p.make.toLowerCase())) score += 10;
  if (p.model && title.toLowerCase().includes(p.model.toLowerCase().split(' ')[0])) score += 10;
  if (p.year_from && title.includes(p.year_from)) score += 5;
  if (p.size && title.includes(p.size)) score += 8;
  if (p.oem && title.includes(p.oem)) score += 10;
  return Math.min(score, 73); // Max 73 points from density
}

function lengthScore(len) {
  if (len >= 50 && len <= 60) return 27;
  if (len >= 45 && len < 50)  return 20;
  if (len > 60 && len <= 65)  return 18;
  if (len >= 40 && len < 45)  return 12;
  if (len > 65 && len <= 70)  return 8;
  return 0;
}

function scoreSEO(title, p) {
  return Math.min(100, lengthScore(title.length) + keywordDensityScore(title, p));
}

function getIssues(title, p) {
  const issues = [];
  if (title.length < 35)  issues.push('title_too_short');
  if (title.length > 68)  issues.push('title_too_long');
  if (!p.make)             issues.push('missing_make');
  if (!p.brand)            issues.push('missing_brand');
  if (!p.model)            issues.push('missing_model');
  if (!p.year_from)        issues.push('missing_year');
  if (!p.category)         issues.push('missing_category');
  return issues;
}

function needsAI(score, issues) {
  return score < (config.AI_SCORE_THRESHOLD || 65) ||
    issues.includes('missing_make') ||
    issues.includes('missing_brand');
}

function slugify(str) {
  return (str || '')
    .toLowerCase()
    .replace(/ä/g,'ae').replace(/ö/g,'oe').replace(/ü/g,'ue')
    .replace(/ñ/g,'n').replace(/[àáâ]/g,'a').replace(/[èéê]/g,'e')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '');
}

function buildSchema(p, nlTitle, metaNl, url) {
  const schema = {
    '@context': 'https://schema.org/',
    '@type': 'Product',
    name: nlTitle,
    sku: p.sku,
    ...(p.oem ? { mpn: p.oem } : {}),
    brand: { '@type': 'Brand', name: p.brand || 'Origineel' },
    description: metaNl,
    url: url,
    ...(p.price ? {
      offers: {
        '@type': 'Offer',
        url: url,
        priceCurrency: 'EUR',
        price: parseFloat(p.price).toFixed(2),
        availability: p.stock === 'in_stock'
          ? 'https://schema.org/InStock'
          : 'https://schema.org/LimitedAvailability',
        seller: { '@type': 'Organization', name: config.SHOP_NAME }
      }
    } : {})
  };
  if (p.make || p.model) {
    schema.vehicleApplicationInfo = [
      {
        '@type': 'VehicleApplicationInfo',
        vehicleMake: p.make,
        vehicleModel: p.model,
        ...(p.year_from ? { productionDate: p.year_from } : {}),
        ...(p.year_to   ? { discontinuedDate: p.year_to } : {}),
        ...(p.engine    ? { engineName: p.engine } : {})
      }
    ];
  }
  return JSON.stringify(schema, null, 2);
}

function buildChannableRow(p, titles, metaNl) {
  return {
    id:              p.sku,
    title:           titles.nl || '',
    title_be:        titles.be || titles.nl || '',
    title_de:        titles.de || '',
    title_en:        titles.en || '',
    description:     metaNl,
    brand:           p.brand,
    mpn:             p.oem || '',
    custom_label_0:  p.category,
    custom_label_1:  p.make,
    custom_label_2:  p.brand,
    custom_label_3:  p.year_from && p.year_to ? `${p.year_from}-${p.year_to}` : '',
    custom_label_4:  p.stock === 'in_stock' ? 'in_stock' : 'low_stock',
    item_group_id:   p.sku.replace(/-[^-]*$/, ''),
    condition:       'new'
  };
}

// ── MAIN PROCESSING ───────────────────────────────────────────
const markets = config.MARKETS || ['nl'];
const titlesSeen = {}; // for dedup

const results = skus.map(p => {
  const intent = detectIntent(p.category);

  // Generate titles per market
  const titles = {};
  const variants = {}; // A/B variant per market

  for (const market of markets) {
    const formulaSet = (FORMULAS[market] || FORMULAS.nl)[intent] || FORMULAS.nl.transactional;
    // Primary title = best formula
    titles[market] = selectBestTitle(formulaSet, p, market);
    // Variant B = second best formula (different index)
    if (config.ENABLE_AB_VARIANTS && formulaSet.length > 1) {
      const altFormulas = formulaSet.filter((_, i) => i !== 0);
      variants[market] = selectBestTitle(altFormulas, p, market);
    }
  }

  const primaryTitle = titles[config.PRIMARY_LANGUAGE || 'nl'] || titles[markets[0]];

  // Meta descriptions per market
  const metas = {};
  for (const market of markets) {
    const metaSet = (META[market] || META.nl)[intent] || META.nl.transactional;
    metas[market] = applyTemplate(metaSet, p, market);
  }
  const primaryMeta = metas[config.PRIMARY_LANGUAGE || 'nl'] || metas[markets[0]];

  // Quality scoring
  const score  = scoreSEO(primaryTitle, p);
  const issues = getIssues(primaryTitle, p);
  const charStatus = primaryTitle.length >= 50 && primaryTitle.length <= 60 ? 'optimal'
    : primaryTitle.length >= 40 && primaryTitle.length <= 65 ? 'acceptable' : 'fix_needed';

  // Duplicate detection
  const isDup = !!titlesSeen[primaryTitle.toLowerCase()];
  if (!isDup) titlesSeen[primaryTitle.toLowerCase()] = p.sku;
  else issues.push('duplicate_title');

  // URL & Schema
  const urlSlug = slugify(`${p.brand}-${p.part_name}-${p.make}-${p.model}`);
  const url     = `${config.BASE_URL}/${slugify(p.category)}/${urlSlug}`;
  const schema  = buildSchema(p, primaryTitle, primaryMeta, url);

  // Channable row
  const channable = buildChannableRow(p, titles, primaryMeta);

  // Magento 2 row
  const magento = {
    sku: p.sku, name: primaryTitle,
    meta_title: primaryTitle, meta_description: primaryMeta,
    url_key: urlSlug
  };

  return {
    // Identifiers
    sku: p.sku, oem: p.oem || '', price: p.price || '', stock: p.stock,
    // Titles per market
    titles, variants,
    primary_title: primaryTitle,
    // Metas
    metas, primary_meta: primaryMeta,
    // URL & Schema
    url, url_key: urlSlug, schema_json: schema,
    // Quality
    seo_score: score, char_count: primaryTitle.length,
    char_status: charStatus, intent, issues,
    issues_count: issues.length,
    needs_ai: needsAI(score, issues),
    is_duplicate: isDup,
    // Exports
    channable, magento,
    // Product data (pass-through)
    product: p
  };
});

// Batch-level stats
const stats = {
  batch_index: $json.batch_index,
  batch_total: $json.batch_total,
  total_skus:  $json.total_skus,
  processed:   results.length,
  optimal:     results.filter(r => r.char_status === 'optimal').length,
  acceptable:  results.filter(r => r.char_status === 'acceptable').length,
  fix_needed:  results.filter(r => r.char_status === 'fix_needed').length,
  avg_score:   Math.round(results.reduce((s,r) => s + r.seo_score, 0) / results.length),
  needs_ai:    results.filter(r => r.needs_ai).length,
  duplicates:  results.filter(r => r.is_duplicate).length,
  intents:     {
    transactional: results.filter(r => r.intent === 'transactional').length,
    commercial:    results.filter(r => r.intent === 'commercial').length,
    navigational:  results.filter(r => r.intent === 'navigational').length,
    informational: results.filter(r => r.intent === 'informational').length
  }
};

return [{ json: { results, stats, config } }];

// Split results into individual items for per-SKU processing
const { results, stats, config } = $json;
return results.map(r => ({ json: { ...r, _stats: stats, _config: config } }));

// ============================================================
// MERGE AI RESPONSE into SKU item
// ============================================================
const item = $json;

// The AI response comes from the previous node's text output
// n8n Langchain nodes return content in specific format
let aiData = {};
try {
  // Try to get AI response — it may be in different places depending on node version
  const aiText = item.text || item.content || item.message?.content || '';
  const jsonMatch = aiText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    aiData = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  aiData = { improved_title: '', reasoning: 'Parse error' };
}

const original = item;

// Apply AI improvements if they're better
const aiTitle = aiData.improved_title || '';
const useAiTitle = aiTitle.length >= 35 && aiTitle.length <= 75;

if (useAiTitle) {
  original.primary_title = aiTitle;
  original.titles = { ...original.titles, nl: aiTitle };
  if (aiData.improved_title_de) original.titles.de = aiData.improved_title_de;
  if (aiData.variant_b) original.variants = { ...original.variants, nl: aiData.variant_b };
  if (aiData.inferred_make && !original.product.make) original.product.make = aiData.inferred_make;
  if (aiData.inferred_model && !original.product.model) original.product.model = aiData.inferred_model;
  original.ai_enriched = true;
  original.ai_reasoning = aiData.reasoning || '';
  original.ai_title_applied = true;
} else {
  original.ai_enriched = true;
  original.ai_title_applied = false;
  original.ai_reasoning = aiData.reasoning || 'AI title not usable, kept original';
}

return [{ json: original }];

// ============================================================
// FINAL FORMATTER — prepare all export formats
// ============================================================
const r = $json;
const markets = r._config?.MARKETS || ['nl'];

// Final quality check after possible AI enrichment
function finalCharClass(len) {
  if (len >= 50 && len <= 60) return 'optimal';
  if (len >= 40 && len <= 65) return 'acceptable';
  return 'fix_needed';
}

const finalLen = r.primary_title.length;

// Build Google Sheets row
const sheetsRow = {
  sku:          r.sku,
  title_nl:     r.titles?.nl || r.primary_title,
  title_be:     r.titles?.be || r.titles?.nl || '',
  title_de:     r.titles?.de || '',
  title_en:     r.titles?.en || '',
  variant_b_nl: r.variants?.nl || '',
  variant_b_de: r.variants?.de || '',
  meta_nl:      r.metas?.nl || r.primary_meta,
  meta_de:      r.metas?.de || '',
  seo_score:    r.seo_score,
  char_count:   finalLen,
  char_status:  finalCharClass(finalLen),
  intent:       r.intent,
  issues:       r.issues?.join(' | ') || '',
  is_duplicate: r.is_duplicate ? 'YES' : '',
  ai_enriched:  r.ai_enriched ? 'YES' : '',
  ai_reasoning: r.ai_reasoning || '',
  url_key:      r.url_key,
  canonical:    r.url,
  status:       r.issues?.length === 0 ? '✅ optimal' : '⚠️ review',
  updated_at:   new Date().toISOString().split('T')[0]
};

return [{
  json: {
    ...r,
    char_status: finalCharClass(finalLen),
    sheets_row: sheetsRow,
    final: true
  }
}];

// ============================================================
// AGGREGATE — collect all processed SKUs into final response
// ============================================================
const items = $input.all();

const results = items.map(i => i.json);

// Stats
const total = results.length;
const optimal    = results.filter(r => r.char_status === 'optimal').length;
const acceptable = results.filter(r => r.char_status === 'acceptable').length;
const fixNeeded  = results.filter(r => r.char_status === 'fix_needed').length;
const aiEnriched = results.filter(r => r.ai_enriched).length;
const duplicates = results.filter(r => r.is_duplicate).length;
const avgScore   = Math.round(results.reduce((s,r) => s + r.seo_score, 0) / total);

// Build clean export arrays
const channable = results.map(r => r.channable);
const magento2  = results.map(r => r.magento);
const gmc       = results.map(r => ({
  id: r.sku,
  title: r.primary_title,
  description: r.primary_meta
}));
const seoReport = results.map(r => ({
  sku:          r.sku,
  primary_title: r.primary_title,
  title_nl:     r.titles?.nl || '',
  title_be:     r.titles?.be || '',
  title_de:     r.titles?.de || '',
  title_en:     r.titles?.en || '',
  variant_b:    r.variants?.nl || '',
  meta_nl:      r.metas?.nl || r.primary_meta,
  char_count:   r.char_count,
  seo_score:    r.seo_score,
  char_status:  r.char_status,
  intent:       r.intent,
  issues:       Array.isArray(r.issues) ? r.issues.join(' | ') : '',
  ai_enriched:  r.ai_enriched,
  ai_reasoning: r.ai_reasoning || '',
  is_duplicate: r.is_duplicate,
  url:          r.url
}));

const schema_blocks = results.map(r => ({
  sku: r.sku,
  schema_json: r.schema_json
}));

const response = {
  success: true,
  generated_at: new Date().toISOString(),
  version: 'v2',
  shop: 'connectcarparts.nl',
  summary: {
    total,
    optimal,
    acceptable,
    fix_needed: fixNeeded,
    avg_score: avgScore,
    ai_enriched: aiEnriched,
    duplicates,
    pass_rate_pct: Math.round((optimal + acceptable) / total * 100)
  },
  exports: {
    channable,
    magento2,
    google_merchant_center: gmc,
    schema_blocks,
    seo_report: seoReport
  },
  results
};

return [{ json: response }];

// ============================================================
// ERROR HANDLER — catches failures and logs them
// Connect this to the 'error' output of critical nodes
// ============================================================
const error = $json.error || {};
const context = $json;

console.error('AutoSEO Brain v2 ERROR:', JSON.stringify({
  timestamp: new Date().toISOString(),
  sku: context.sku || 'unknown',
  error_message: error.message || 'Unknown error',
  node: error.node?.name || 'unknown'
}, null, 2));

// Return error info so the run doesn't silently die
return [{ json: {
  error: true,
  sku: context.sku || 'unknown',
  error_message: error.message || 'Unknown error',
  timestamp: new Date().toISOString()
} }];

// Summary log for schedule runs
const s = $json.summary || {};
console.log(`AutoSEO Brain v2 Complete\n` +
  `Total: ${s.total} | Optimal: ${s.optimal} | Score: ${s.avg_score}/100\n` +
  `AI enriched: ${s.ai_enriched} | Duplicates: ${s.duplicates} | Pass rate: ${s.pass_rate_pct}%`);
return [$input.item];
